                         return View(course);
                     }
                     try
                     {
                         var uploadsPath = Path.Combine(_env.WebRootPath ?? _env.ContentRootPath, "Uploads", "TeachingMaterials");
                         Directory.CreateDirectory(uploadsPath);
                         var fileName = $"course_{course.CourseID}_{Guid.NewGuid()}{fileExtension}";
