using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    /// <summary>
    /// Creates a fresh InMemory SchoolContext for each test, optionally seeded with data.
    /// </summary>
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(bool seed = false)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();

            if (seed)
                SeedData(context);

            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructors = new[]
            {
                new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") },
                new Instructor { FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06") },
            };
            context.Instructors.AddRange(instructors);
            context.SaveChanges();

            var departments = new[]
            {
                new Department { Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[0].ID },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[1].ID },
            };
            context.Departments.AddRange(departments);
            context.SaveChanges();

            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = departments[0].DepartmentID },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = departments[1].DepartmentID },
            };
            context.Courses.AddRange(courses);
            context.SaveChanges();

            var students = new[]
            {
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
            };
            context.Students.AddRange(students);
            context.SaveChanges();

            var enrollments = new[]
            {
                new Enrollment { StudentID = students[0].ID, CourseID = 1050, Grade = Grade.A },
                new Enrollment { StudentID = students[1].ID, CourseID = 4022, Grade = Grade.B },
            };
            context.Enrollments.AddRange(enrollments);
            context.SaveChanges();

            var officeAssignment = new OfficeAssignment { InstructorID = instructors[1].ID, Location = "Smith 17" };
            context.OfficeAssignments.Add(officeAssignment);
            context.SaveChanges();

            var courseAssignments = new[]
            {
                new CourseAssignment { CourseID = 1050, InstructorID = instructors[0].ID },
                new CourseAssignment { CourseID = 4022, InstructorID = instructors[1].ID },
            };
            context.CourseAssignments.AddRange(courseAssignments);
            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _sut;

        public NotificationServiceTests()
        {
            _sut = new NotificationService();
            // Drain any leftover notifications from other tests (static queue)
            while (_sut.ReceiveNotification() != null) { }
        }

        public void Dispose() => _sut.Dispose();

        [Fact]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

            var notification = _sut.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
            Assert.Contains("updated", notification.Message);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_Delete_GeneratesCorrectMessage()
        {
            _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "User1");

            var notification = _sut.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("deleted", notification.Message);
            Assert.Contains("Engineering", notification.Message);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();

            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.Equal("A", first!.EntityType);
            Assert.Equal("B", second!.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation; verify it does not throw
            var ex = Record.Exception(() => _sut.MarkAsRead(999));
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _sut.SendNotification("Test", "1", null, EntityOperation.CREATE, null);

            var notification = _sut.ReceiveNotification();

            Assert.Equal("System", notification!.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToNow()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _sut.ReceiveNotification();

            Assert.InRange(notification!.CreatedAt, before, after);
        }
    }
}

using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(1, result[0]);
            Assert.Equal(10, result[9]);
        }

        [Fact]
        public void Create_MiddlePage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(11, result[0]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

            Assert.Equal(5, result.Count);
            Assert.Equal(3, result.PageIndex);
            Assert.Equal(21, result[0]);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void Create_ExactlyOnePageOfItems_SinglePage()
        {
            var source = Enumerable.Range(1, 10).AsQueryable();

            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            Assert.Equal(10, result.Count);
            Assert.Equal(1, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<int> { 1, 2, 3 };

            var result = new PaginatedList<int>(items, count: 30, pageIndex: 2, pageSize: 10);

            Assert.Equal(3, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
        }
    }
}

