using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            // Drain any residual notifications from the static queue
            JsonResult? drainResult;
            do
            {
                drainResult = _controller.GetNotifications();
            } while (GetNotificationCount(drainResult) > 0);

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var value = result.Value;
            Assert.NotNull(value);
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp!.GetValue(value)!);
            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProp!.GetValue(value)!);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Drain first
            JsonResult? drainResult;
            do
            {
                drainResult = _controller.GetNotifications();
            } while (GetNotificationCount(drainResult) > 0);

            // Enqueue via the controller's inherited notificationService
            // Use a StudentsController to send a notification, then read via NotificationsController
            using var studentCtx = TestDbContextFactory.Create(seed: true);
            var studentController = new StudentsController(studentCtx);
            var student = studentCtx.Students.First();
            studentController.DeleteConfirmed(student.ID);
            studentController.Dispose();

            var result = _controller.GetNotifications();
            Assert.NotNull(result);
            var value = result.Value;
            var countProp = value!.GetType().GetProperty("count");
            // Should have at least the delete notification
            Assert.True((int)countProp!.GetValue(value)! >= 1);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            var value = result.Value;
            Assert.NotNull(value);
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp!.GetValue(value)!);
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
        }

        private static int GetNotificationCount(JsonResult? result)
        {
            if (result?.Value == null) return 0;
            var countProp = result.Value.GetType().GetProperty("count");
            if (countProp == null) return 0;
            return (int)countProp.GetValue(result.Value)!;
        }
    }
}

