using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.Create(seed: true);
            _envMock = new Mock<IWebHostEnvironment>();
            _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
            _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
            _loggerMock = new Mock<ILogger<CoursesController>>();

            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // ---- Index ----

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<IEnumerable<Course>>(result.Model);
            Assert.True(model.Any());
        }

        // ---- Details ----

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourse()
        {
            var course = _context.Courses.First();

            var result = _controller.Details(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        // ---- Create GET ----

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // ---- Create POST ----

        [Fact]
        public void Create_Post_ValidCourse_NoFile_RedirectsToIndex()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 9999,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Create(course, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Contains(_context.Courses, c => c.CourseID == 9999);
        }

        [Fact]
        public void Create_Post_InvalidExtension_AddsModelError()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 8888,
                Title = "Upload Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = CreateMockFile("test.exe", 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_AddsModelError()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 7777,
                Title = "Big File",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = CreateMockFile("big.jpg", 6 * 1024 * 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_ValidImage_SavesFileAndRedirects()
        {
            var dept = _context.Departments.First();
            var course = new Course
            {
                CourseID = 6666,
                Title = "With Image",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = CreateMockFile("photo.png", 1024);

            var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var saved = _context.Courses.Find(6666);
            Assert.NotNull(saved);
            Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 5555, Credits = 3 };

            var result = _controller.Create(course, null!) as ViewResult;

            Assert.NotNull(result);
        }

        // ---- Edit GET ----

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsCourse()
        {
            var course = _context.Courses.First();

            var result = _controller.Edit(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        // ---- Edit POST ----

        [Fact]
        public void Edit_Post_ValidCourse_NoFile_RedirectsToIndex()
        {
            var course = _context.Courses.First();
            // Detach to simulate a form post
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            course.Title = "Updated Title";

            var result = _controller.Edit(course, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidExtension_AddsModelError()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var fileMock = CreateMockFile("bad.txt", 1024);

            var result = _controller.Edit(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_FileTooLarge_AddsModelError()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var fileMock = CreateMockFile("big.jpg", 6 * 1024 * 1024);

            var result = _controller.Edit(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            _controller.ModelState.AddModelError("Title", "Required");

            var result = _controller.Edit(course, null!) as ViewResult;

            Assert.NotNull(result);
        }

        // ---- Delete GET ----

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsCourse()
        {
            var course = _context.Courses.First();

            var result = _controller.Delete(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        // ---- DeleteConfirmed ----

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var course = _context.Courses.First();

            var result = _controller.DeleteConfirmed(course.CourseID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Courses.Find(course.CourseID));
        }

        // ---- Helper ----

        private static Mock<IFormFile> CreateMockFile(string fileName, long length)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(length);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return mock;
        }
    }
}

