using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create(seed: true);
            _controller = new InstructorsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // ---- Index ----

        [Fact]
        public void Index_NoSelection_ReturnsAllInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.True(model.Instructors.Any());
            Assert.Null(model.Courses);
            Assert.Null(model.Enrollments);
        }

        [Fact]
        public void Index_WithInstructorId_ReturnsCourses()
        {
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.CourseAssignments.Any());

            var result = _controller.Index(instructor.ID, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.True(model.Courses.Any());
        }

        [Fact]
        public void Index_WithInstructorIdAndCourseId_ReturnsEnrollments()
        {
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                    .ThenInclude(ca => ca.Course)
                        .ThenInclude(c => c.Enrollments)
                .First(i => i.CourseAssignments.Any());

            var courseWithEnrollments = instructor.CourseAssignments
                .Select(ca => ca.Course)
                .FirstOrDefault(c => c.Enrollments != null && c.Enrollments.Any());

            if (courseWithEnrollments != null)
            {
                var result = _controller.Index(instructor.ID, courseWithEnrollments.CourseID) as ViewResult;

                Assert.NotNull(result);
                var model = Assert.IsType<InstructorIndexData>(result.Model);
                Assert.NotNull(model.Enrollments);
                Assert.True(model.Enrollments.Any());
            }
        }

        // ---- Details ----

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Details(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        // ---- Create GET ----

        [Fact]
        public void Create_Get_ReturnsViewWithCourseData()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // ---- Create POST ----

        [Fact]
        public void Create_Post_ValidInstructor_NoSelectedCourses_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 1)
            };

            var result = _controller.Create(instructor, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Contains(_context.Instructors, i => i.LastName == "Instructor");
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            var course = _context.Courses.First();
            var instructor = new Instructor
            {
                FirstMidName = "Course",
                LastName = "Teacher",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, new[] { course.CourseID.ToString() }) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.LastName == "Teacher");
            Assert.Single(saved.CourseAssignments);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!) as ViewResult;

            Assert.NotNull(result);
        }

        // ---- Edit GET ----

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsInstructorWithCourseData()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Edit((int?)instructor.ID) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // ---- Delete GET ----

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsInstructor()
        {
            var instructor = _context.Instructors.First();

            var result = _controller.Delete(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        // ---- DeleteConfirmed ----

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Use instructor that is NOT a department administrator (or handle nulling out the FK)
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First();

            var result = _controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Instructors.Find(instructor.ID));
        }

        [Fact]
        public void DeleteConfirmed_InstructorIsDepartmentAdmin_NullsOutForeignKey()
        {
            // Instructor[0] (Abercrombie) is English dept admin
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.LastName == "Abercrombie");

            var dept = _context.Departments.First(d => d.InstructorID == instructor.ID);

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept!.InstructorID);
        }
    }
}

