using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanCreateContext_WithInMemoryProvider()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context);
        }

        [Fact]
        public void Students_CRUD_Operations()
        {
            using var context = TestDbContextFactory.Create();

            // Create
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2024, 1, 1)
            };
            context.Students.Add(student);
            context.SaveChanges();
            Assert.True(student.ID > 0);

            // Read
            var found = context.Students.Find(student.ID);
            Assert.NotNull(found);
            Assert.Equal("Test", found.FirstMidName);

            // Update
            found.LastName = "Updated";
            context.SaveChanges();
            var updated = context.Students.Find(student.ID);
            Assert.Equal("Updated", updated!.LastName);

            // Delete
            context.Students.Remove(updated);
            context.SaveChanges();
            Assert.Null(context.Students.Find(student.ID));
        }

        [Fact]
        public void Courses_WithDepartment_Relationship()
        {
            using var context = TestDbContextFactory.Create(seed: true);

            var course = context.Courses.Include(c => c.Department).First();
            Assert.NotNull(course.Department);
        }

        [Fact]
        public void Enrollments_LinkStudentAndCourse()
        {
            using var context = TestDbContextFactory.Create(seed: true);

            var enrollment = context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First();

            Assert.NotNull(enrollment.Student);
            Assert.NotNull(enrollment.Course);
        }

        [Fact]
        public void CourseAssignment_CompositeKey()
        {
            using var context = TestDbContextFactory.Create(seed: true);

            var ca = context.CourseAssignments.First();
            Assert.True(ca.CourseID > 0);
            Assert.True(ca.InstructorID > 0);
        }

        [Fact]
        public void Instructor_HasOfficeAssignment()
        {
            using var context = TestDbContextFactory.Create(seed: true);

            var instructor = context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.OfficeAssignment != null);

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.NotEmpty(instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void Department_HasAdministrator()
        {
            using var context = TestDbContextFactory.Create(seed: true);

            var dept = context.Departments
                .Include(d => d.Administrator)
                .First(d => d.InstructorID != null);

            Assert.NotNull(dept.Administrator);
        }

        [Fact]
        public void Person_FullName_ReturnsLastCommaFirst()
        {
            using var context = TestDbContextFactory.Create(seed: true);

            var student = context.Students.First();
            Assert.Equal($"{student.LastName}, {student.FirstMidName}", student.FullName);
        }
    }

    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_EmptyDb_SeedsData()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.True(context.Students.Any());
            Assert.True(context.Instructors.Any());
            Assert.True(context.Departments.Any());
            Assert.True(context.Courses.Any());
            Assert.True(context.Enrollments.Any());
        }

        [Fact]
        public void Initialize_AlreadySeeded_DoesNotDuplicate()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);
            var countBefore = context.Students.Count();

            DbInitializer.Initialize(context);
            var countAfter = context.Students.Count();

            Assert.Equal(countBefore, countAfter);
        }
    }
}

