using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class ModelTests
    {
        [Fact]
        public void Person_FullName_FormatsCorrectly()
        {
            var student = new Student { FirstMidName = "John", LastName = "Doe" };
            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_TrueWhenSet()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_EnumValues_AreValid(Grade grade)
        {
            Assert.True(Enum.IsDefined(typeof(Grade), grade));
        }

        [Theory]
        [InlineData(EntityOperation.CREATE)]
        [InlineData(EntityOperation.UPDATE)]
        [InlineData(EntityOperation.DELETE)]
        public void EntityOperation_EnumValues_AreValid(EntityOperation op)
        {
            Assert.True(Enum.IsDefined(typeof(EntityOperation), op));
        }

        [Fact]
        public void Course_Properties_DefaultValues()
        {
            var course = new Course();
            Assert.Equal(0, course.CourseID);
            Assert.Null(course.Title);
            Assert.Equal(0, course.Credits);
        }

        [Fact]
        public void Department_RowVersion_NullByDefault()
        {
            var dept = new Department();
            Assert.Null(dept.RowVersion);
        }

        [Fact]
        public void Notification_DefaultValues()
        {
            var notification = new Notification();
            Assert.Equal(0, notification.Id);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Enrollment_NullableGrade()
        {
            var enrollment = new Enrollment();
            Assert.Null(enrollment.Grade);

            enrollment.Grade = Grade.A;
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void OfficeAssignment_Properties()
        {
            var oa = new OfficeAssignment { InstructorID = 1, Location = "Room 101" };
            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Room 101", oa.Location);
        }

        [Fact]
        public void Instructor_Collections_CanBeInitialized()
        {
            var instructor = new Instructor
            {
                CourseAssignments = new List<CourseAssignment>()
            };
            Assert.NotNull(instructor.CourseAssignments);
            Assert.Empty(instructor.CourseAssignments);
        }

        [Fact]
        public void Student_Collections_CanBeInitialized()
        {
            var student = new Student
            {
                Enrollments = new List<Enrollment>()
            };
            Assert.NotNull(student.Enrollments);
            Assert.Empty(student.Enrollments);
        }
    }
}

